        "# --- Correlation heatmap ---\n",
        "\n",
        "# Pick a reasonable subset of numeric columns for clarity\n",
        "numeric = ib.select_dtypes(include=[np.number]).copy()\n",
        "# Filter columns that are mostly constant / empty\n",
        "numeric = numeric.loc[:, numeric.nunique(dropna=True) > 5]\n",
        "\n",
        "corr = numeric.corr(numeric_only=True)\n",
        "# Focus view if the matrix is very large\n",
        "if corr.shape[0] > 20:\n",
        "    # Try keep a compact set with target + a few likely predictors\n",
        "    keep = [c for c in corr.columns if c in [wind_col, pres_col, sst_col, \"lat\", \"lon\", \"era5_u10\", \"era5_v10\", \"era5_wind10_ms\", \"era5_msl_hpa\", \"month_sin\", \"month_cos\"]]\n",
        "    keep = [c for c in keep if c in corr.columns]\n",
        "    corr = corr.loc[keep, keep]\n",
        "\n",
        "fig, ax = plt.subplots(figsize=(8,6))\n",
        "sns.heatmap(corr, annot=False, cmap=\"coolwarm\", center=0, ax=ax)\n",
        "ax.set_title(\"Correlation Heatmap (selected variables)\")\n",
        "plt.tight_layout()\n",
        "plt.savefig(FIGDIR / \"corr_heatmap.png\")\n",
        "plt.show()\n",
