        "    # Identify target and feature columns\n",
        "    target_col = get_first_match(train_df, [\"wind_knots\", \"target\", \"max_wind\"])\n",
        "    # Drop clear non-features if present\n",
        "    drop_like = {\"sid\",\"name\",\"basin_name\",\"storm\",\"time\",\"time_naive\",\"valid_time\",\"season\"}\n",
        "    feature_cols = [c for c in train_df.columns if c != target_col and c.lower() not in drop_like]\n",
        "    X = train_df[feature_cols].copy()\n",
        "    y = train_df[target_col].values\n",
        "\n",
        "    # Keep only numeric columns (one-hots + numeric)\n",
        "    X = X.select_dtypes(include=[np.number])\n",
        "\n",
        "    # RandomForest importances\n",
        "    from sklearn.ensemble import RandomForestRegressor\n",
        "    rf = RandomForestRegressor(n_estimators=300, random_state=42, n_jobs=-1)\n",
        "    rf.fit(X, y)\n",
        "    imp_rf = pd.Series(rf.feature_importances_, index=X.columns).sort_values(ascending=False)[:15]\n",
        "\n",
        "    fig, ax = plt.subplots(figsize=(8,6))\n",
        "    imp_rf.sort_values().plot(kind=\"barh\", ax=ax, color=\"#4C72B0\")\n",
        "    ax.set_title(\"RandomForest — Top Feature Importances\")\n",
        "    ax.set_xlabel(\"Importance\")\n",
        "    plt.tight_layout()\n",
        "    plt.savefig(FIGDIR / \"featimp_randomforest.png\")\n",
        "    plt.show()\n",
        "    print(\"Saved: featimp_randomforest.png\")\n",
        "\n",
        "    # LightGBM importances (if available)\n",
        "    try:\n",
        "        import lightgbm as lgb\n",
        "        lgbm = lgb.LGBMRegressor(random_state=42)\n",
